package com.example
import io.ktor.server.engine.embeddedServer import io.ktor.server.netty.Netty
fun main() { embeddedServer( factory = Netty, host = "0.0.0.0", port = 8080, module = Application::module ).start(wait = true) }

package com.example.controller

import com.example.model.EventRequest
import com.example.service.EventService
import com.example.view.toView
import io.ktor.http.HttpStatusCode
import io.ktor.server.request.receive
import io.ktor.server.response.respond
import io.ktor.server.routing.Route
import io.ktor.server.routing.delete
import io.ktor.server.routing.get
import io.ktor.server.routing.post
import io.ktor.server.routing.put
import io.ktor.server.routing.route

class EventController(private val service: EventService) {
    fun register(route: Route) {
        route.route("/api/events") {
            get {
                call.respond(service.listEvents().map { it.toView() })
            }

            get("/{id}") {
                val id = call.parameters["id"]?.toLongOrNull()
                    ?: return@get call.respond(HttpStatusCode.BadRequest, mapOf("error" to "invalid event id"))

                val event = service.getEvent(id)
                    ?: return@get call.respond(HttpStatusCode.NotFound, mapOf("error" to "event not found"))

                call.respond(event.toView())
            }

            post {
                val request = call.receive<EventRequest>()
                val created = service.createEvent(request)
                call.respond(HttpStatusCode.Created, created.toView())
            }

            put("/{id}") {
                val id = call.parameters["id"]?.toLongOrNull()
                    ?: return@put call.respond(HttpStatusCode.BadRequest, mapOf("error" to "invalid event id"))

                val request = call.receive<EventRequest>()
                val updated = service.updateEvent(id, request)
                    ?: return@put call.respond(HttpStatusCode.NotFound, mapOf("error" to "event not found"))

                call.respond(updated.toView())
            }

            delete("/{id}") {
                val id = call.parameters["id"]?.toLongOrNull()
                    ?: return@delete call.respond(HttpStatusCode.BadRequest, mapOf("error" to "invalid event id"))

                if (!service.deleteEvent(id)) {
                    return@delete call.respond(HttpStatusCode.NotFound, mapOf("error" to "event not found"))
                }

                call.respond(HttpStatusCode.NoContent)
            }
        }
    }
}

package com.example.db

import com.zaxxer.hikari.HikariConfig
import com.zaxxer.hikari.HikariDataSource
import javax.sql.DataSource

object DatabaseFactory {
    fun createPostgresDataSource(): DataSource {
        val config = HikariConfig().apply {
            jdbcUrl = System.getenv("DATABASE_URL") ?: "jdbc:postgresql://localhost:5432/utcnevents"
            username = System.getenv("DATABASE_USER") ?: "postgres"
            password = System.getenv("DATABASE_PASSWORD") ?: "postgres"
            driverClassName = "org.postgresql.Driver"
            maximumPoolSize = 5
            isAutoCommit = true
            transactionIsolation = "TRANSACTION_READ_COMMITTED"
            validate()
        }
        return HikariDataSource(config)
    }

    fun initializeSchema(dataSource: DataSource) {
        val schemaSql = this::class.java.classLoader
            .getResource("db/schema.sql")
            ?.readText()
            ?: error("Missing db/schema.sql resource")

        dataSource.connection.use { connection ->
            connection.createStatement().use { statement ->
                statement.execute(schemaSql)
            }
        }
    }
}

package com.example.model
import kotlinx.serialization.Serializable
@Serializable data class EventRequest( val title: String, val description: String, val date: String, val category: String, val department: String )

package com.example.repository

import com.example.model.Event

interface EventRepository {
    fun findAll(): List<Event>
    fun findById(id: Long): Event?
    fun create(event: Event): Event
    fun update(id: Long, event: Event): Event?
    fun delete(id: Long): Boolean
}

class InMemoryEventRepository : EventRepository {
    private val events = linkedMapOf<Long, Event>()
    private var nextId = 1L

    override fun findAll(): List<Event> = events.values.toList()

    override fun findById(id: Long): Event? = events[id]

    override fun create(event: Event): Event {
        val stored = event.copy(id = nextId++)
        events[stored.id] = stored
        return stored
    }

    override fun update(id: Long, event: Event): Event? {
        if (!events.containsKey(id)) return null
        val updated = event.copy(id = id)
        events[id] = updated
        return updated
    }

    override fun delete(id: Long): Boolean = events.remove(id) != null
}

package com.example.repository
import com.example.model.Event import javax.sql.DataSource
class PostgresEventRepository(private val dataSource: DataSource) : EventRepository { override fun findAll(): List<Event> = dataSource.connection.use { connection -> connection.prepareStatement( """ SELECT id, title, description, date, category, department FROM events ORDER BY id """.trimIndent() ).use { statement -> statement.executeQuery().use { rs -> buildList { while (rs.next()) { add(rs.toEvent()) } } } } }
override fun findById(id: Long): Event? = dataSource.connection.use { connection -> connection.prepareStatement( """ SELECT id, title, description, date, category, department FROM events WHERE id = ? """.trimIndent() ).use { statement -> statement.setLong(1, id) statement.executeQuery().use { rs -> if (rs.next()) rs.toEvent() else null } } }
override fun create(event: Event): Event = dataSource.connection.use { connection -> connection.prepareStatement( """ INSERT INTO events(title, description, date, category, department) VALUES (?, ?, ?, ?, ?) RETURNING id, title, description, date, category, department """.trimIndent() ).use { statement -> statement.setString(1, event.title) statement.setString(2, event.description) statement.setString(3, event.date) statement.setString(4, event.category) statement.setString(5, event.department) statement.executeQuery().use { rs -> rs.next() rs.toEvent() } } }
override fun update(id: Long, event: Event): Event? = dataSource.connection.use { connection -> connection.prepareStatement( """ UPDATE events SET title = ?, description = ?, date = ?, category = ?, department = ? WHERE id = ? RETURNING id, title, description, date, category, department """.trimIndent() ).use { statement -> statement.setString(1, event.title) statement.setString(2, event.description) statement.setString(3, event.date) statement.setString(4, event.category) statement.setString(5, event.department) statement.setLong(6, id) statement.executeQuery().use { rs -> if (rs.next()) rs.toEvent() else null } } }
override fun delete(id: Long): Boolean = dataSource.connection.use { connection -> connection.prepareStatement("DELETE FROM events WHERE id = ?").use { statement -> statement.setLong(1, id) statement.executeUpdate() > 0 } }
private fun java.sql.ResultSet.toEvent(): Event = Event( id = getLong("id"), title = getString("title"), description = getString("description"), date = getString("date"), category = getString("category"), department = getString("department") ) }

package com.example.service

import com.example.model.Event
import com.example.model.EventRequest
import com.example.repository.EventRepository

class EventService(private val repository: EventRepository) {
    fun listEvents(): List<Event> = repository.findAll()

    fun getEvent(id: Long): Event? = repository.findById(id)

    fun createEvent(request: EventRequest): Event {
        validate(request)
        return repository.create(request.toEvent(id = 0L))
    }

    fun updateEvent(id: Long, request: EventRequest): Event? {
        validate(request)
        return repository.update(id, request.toEvent(id))
    }

    fun deleteEvent(id: Long): Boolean = repository.delete(id)

    private fun validate(request: EventRequest) {
        require(request.title.isNotBlank()) { "title must not be blank" }
        require(request.date.isNotBlank()) { "date must not be blank" }
        require(request.category.isNotBlank()) { "category must not be blank" }
        require(request.department.isNotBlank()) { "department must not be blank" }
    }

    private fun EventRequest.toEvent(id: Long): Event = Event(
        id = id,
        title = title.trim(),
        description = description.trim(),
        date = date.trim(),
        category = category.trim(),
        department = department.trim()
    )
}

package com.example

import io.ktor.client.request.delete
import io.ktor.client.request.get
import io.ktor.client.request.post
import io.ktor.client.request.put
import io.ktor.client.request.setBody
import io.ktor.client.statement.bodyAsText
import io.ktor.http.ContentType
import io.ktor.http.HttpStatusCode
import io.ktor.http.contentType
import io.ktor.server.testing.testApplication
import kotlin.test.Test
import kotlin.test.assertEquals
import kotlin.test.assertTrue

class ApplicationTest {
    @Test
    fun healthEndpointReturnsOk() = testApplication {
        application {
            module()
        }

        val response = client.get("/health")

        assertEquals(HttpStatusCode.OK, response.status)
        assertTrue(response.bodyAsText().contains("ok"))
    }

    @Test
    fun eventCrudFlowWorks() = testApplication {
        application {
            module()
        }

        val createResponse = client.post("/api/events") {
            contentType(ContentType.Application.Json)
            setBody(
                """
                {
                  "title":"Coding Contest",
                  "description":"Algo challenge",
                  "date":"2026-05-20",
                  "category":"Contest",
                  "department":"CS"
                }
                """.trimIndent()
            )
        }
        assertEquals(HttpStatusCode.Created, createResponse.status)

        val listResponse = client.get("/api/events")
        assertEquals(HttpStatusCode.OK, listResponse.status)
        assertTrue(listResponse.bodyAsText().contains("Coding Contest"))

        val updateResponse = client.put("/api/events/1") {
            contentType(ContentType.Application.Json)
            setBody(
                """
                {
                  "title":"Coding Contest Finals",
                  "description":"Final round",
                  "date":"2026-05-22",
                  "category":"Contest",
                  "department":"CS"
                }
                """.trimIndent()
            )
        }
        assertEquals(HttpStatusCode.OK, updateResponse.status)

        val deleteResponse = client.delete("/api/events/1")
        assertEquals(HttpStatusCode.NoContent, deleteResponse.status)
    }
}
